const ctx = $('Extract Context').first().json;
const filtersRaw = $('Get Group Filters').first()?.json || {};
const rows = ctx.result?.rows || [];

function parseList(v) {
  if (Array.isArray(v)) return v.filter(Boolean);
  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return [];
    try {
      const p = JSON.parse(t);
      return Array.isArray(p) ? p.filter(Boolean) : [t];
    } catch {
      return t.split(',').map(s => s.trim()).filter(Boolean);
    }
  }
  return [];
}

function norm(s) { return String(s || '').toLowerCase(); }

function acceptedSeller(row, sellers) {
  if (!sellers.length) return true;
  const blob = norm(row.seller_text || row.merchant_blob || row.seller || '');
  return sellers.some(s => blob.includes(norm(s)));
}

function keywordOk(row, req, blk) {
  const text = norm([row.title, row.seller_text, row.merchant_blob].filter(Boolean).join(' '));
  for (const k of blk) if (k && text.includes(norm(k))) return false;
  for (const k of req) if (k && !text.includes(norm(k))) return false;
  return true;
}

function priceOk(price, minP, maxP) {
  if (price == null || price === '') return minP == null && maxP == null;
  const p = Number(price);
  if (Number.isNaN(p)) return false;
  if (minP != null && p < Number(minP)) return false;
  if (maxP != null && p > Number(maxP)) return false;
  return true;
}

function shippable(row, f) {
  if (!f.require_shippable) return true;
  if (row.explicit_oos) return false;
  const avail = norm(row.availability_text || '');
  if (/out of stock|currently unavailable|unavailable/.test(avail)) return false;
  const ship = norm(row.shipping_text || '');
  if (f.require_free_shipping && !/free/.test(ship)) return false;
  if (f.require_shipping_signal && !ship && !/delivery|shipping/.test(avail + ship)) return false;
  return true;
}

const f = {
  accepted_sellers: parseList(filtersRaw.accepted_sellers),
  required_keywords: parseList(filtersRaw.required_keywords),
  blacklist_keywords: parseList(filtersRaw.blacklist_keywords),
  blacklist_asins: parseList(filtersRaw.blacklist_asins).map(a => String(a).toUpperCase()),
  min_price: filtersRaw.min_price != null && filtersRaw.min_price !== '' ? Number(filtersRaw.min_price) : null,
  max_price: filtersRaw.max_price != null && filtersRaw.max_price !== '' ? Number(filtersRaw.max_price) : null,
  require_free_shipping: filtersRaw.require_free_shipping === true || filtersRaw.require_free_shipping === 'true',
  require_shipping_signal: filtersRaw.require_shipping_signal === true || filtersRaw.require_shipping_signal === 'true',
  require_shippable: filtersRaw.require_shippable !== false && filtersRaw.require_shippable !== 'false',
};

const filtered = [];
for (const row of rows) {
  const asin = String(row.asin || '').toUpperCase();
  if (!asin || row._skip_update) continue;
  if (f.blacklist_asins.includes(asin)) continue;
  if (!acceptedSeller(row, f.accepted_sellers)) continue;
  if (!keywordOk(row, f.required_keywords, f.blacklist_keywords)) continue;
  if (!priceOk(row.price, f.min_price, f.max_price)) continue;
  if (!shippable(row, f)) continue;
  filtered.push({ ...row, asin });
}

return [{ json: { ...ctx, filtered_rows: filtered, filters_raw: filtersRaw } }];

const item = $('Filter Rows').first().json;
const ctx = $('Extract Context').first().json;
const groupRow = $('Get Group').first()?.json || {};
const filtersRaw = item.filters_raw || {};
const filtered = item.filtered_rows || [];
const stateResp = $('GET State').first().json;
const priorList = Array.isArray(stateResp?.body) ? stateResp.body : (Array.isArray(stateResp) ? stateResp : []);
const priorByAsin = {};
for (const s of priorList) priorByAsin[String(s.asin).toUpperCase()] = s;

function inferStock(row) {
  if (row.explicit_oos) return false;
  const a = String(row.availability_text || '').toLowerCase();
  if (/out of stock|currently unavailable/.test(a)) return false;
  if (/in stock|add to cart|available now/.test(a)) return true;
  return row.price != null;
}

function productUrl(row) {
  return row.product_url || (row.asin ? `https://www.amazon.com/dp/${row.asin}` : null);
}

const notify = groupRow.notify_channel || null;
const group_key = ctx.group_key;
const state_upserts = [];
const price_history = [];
const alerts = [];

const alertNew = filtersRaw.alert_new !== false && filtersRaw.alert_new !== 'false';
const alertStock = filtersRaw.alert_back_in_stock !== false && filtersRaw.alert_back_in_stock !== 'false';
const alertDrop = filtersRaw.alert_price_drop !== false && filtersRaw.alert_price_drop !== 'false';
const dropPct = Number(filtersRaw.price_drop_percent ?? 10) || 10;

for (const row of filtered) {
  const asin = row.asin;
  const prev = priorByAsin[asin];
  const price = row.price != null ? Number(row.price) : null;
  const in_stock = inferStock(row);
  const title = row.title || prev?.title || asin;
  const seller = row.seller_text || row.merchant_blob || prev?.seller || null;
  const image = row.image_url || prev?.image_url || null;
  const url = productUrl(row);

  state_upserts.push({ group_key, asin, title, seller, price, in_stock, image_url: image, product_url: url });
  price_history.push({ group_key, asin, price, in_stock });

  if (!prev && alertNew && in_stock) {
    alerts.push({ group_key, asin, alert_type: 'new_product', title, old_price: null, new_price: price, image_url: image, product_url: url, notify_channel: notify });
  }
  if (prev && !prev.in_stock && in_stock && alertStock) {
    alerts.push({ group_key, asin, alert_type: 'back_in_stock', title, old_price: prev.price ?? null, new_price: price, image_url: image, product_url: url, notify_channel: notify });
  }
  if (prev && prev.price != null && price != null && price < Number(prev.price) && alertDrop) {
    const pct = ((Number(prev.price) - price) / Number(prev.price)) * 100;
    if (pct >= dropPct) {
      alerts.push({ group_key, asin, alert_type: 'price_drop', title, old_price: Number(prev.price), new_price: price, image_url: image, product_url: url, notify_channel: notify });
    }
  }
}

const quality = ctx.scrape_quality || ctx.result?.scrape_quality || 'ok';
const attempt = Number(ctx.attempt ?? ctx.result?.attempt ?? 1);
const needs_recovery = quality !== 'ok' && attempt < 3;

return [{ json: {
  job_id: ctx.job_id,
  group_key,
  kind: ctx.kind,
  run_id: ctx.run_id,
  state_upserts,
  price_history,
  alerts,
  needs_recovery,
  recovery_attempt: attempt + 1,
  scrape_quality: quality,
  attempt,
}}];

const d = $('Diff and Alerts').first().json;
const alerts = d.alerts || [];
if (!alerts.length) return [{ json: { ...d, alert: null, _no_alert: true } }];
return alerts.map(a => ({ json: { ...d, alert: a } }));
